worked_example.final_code:
import java.util.*;

class Product {
    private String sku, name, category;
    private double price;
    private int stock;

    public Product(String sku, String name, String category, double price, int stock) {
        this.sku = sku; this.name = name; this.category = category;
        this.price = price; this.stock = stock;
    }

    public String getSku()      { return sku; }
    public String getName()     { return name; }
    public String getCategory() { return category; }
    public double getPrice()    { return price; }
    public int getStock()       { return stock; }

    @Override public String toString() {
        return "[" + sku + "] " + name + " (" + category + ") ₹" + price + " stock=" + stock;
    }
}

class ProductCatalog {
    private final Map<String, Product> bySku = new HashMap<>();

    public void add(Product p) { bySku.put(p.getSku(), p); }

    public Product findBySku(String sku) { return bySku.get(sku); }

    public boolean hasSku(String sku) { return bySku.containsKey(sku); }

    public Map<String, Integer> stockByCategory() {
        Map<String, Integer> result = new HashMap<>();
        for (Product p : bySku.values()) {
            result.put(p.getCategory(),
                result.getOrDefault(p.getCategory(), 0) + p.getStock());
        }
        return result;
    }

    public Map<String, List<Product>> groupByCategory() {
        Map<String, List<Product>> groups = new HashMap<>();
        for (Product p : bySku.values()) {
            groups.computeIfAbsent(p.getCategory(), k -> new ArrayList<>()).add(p);
        }
        return groups;
    }

    public int size() { return bySku.size(); }
}

public class InventorySystem {
    public static void main(String[] args) {
        ProductCatalog catalog = new ProductCatalog();
        catalog.add(new Product("SKU-001", "Wireless Mouse", "Electronics", 799, 45));
        catalog.add(new Product("SKU-002", "Keyboard", "Electronics", 1999, 12));
        catalog.add(new Product("SKU-003", "Java Programming", "Books", 649, 30));
        catalog.add(new Product("SKU-004", "USB Hub", "Electronics", 499, 60));
        catalog.add(new Product("SKU-005", "Python Cookbook", "Books", 549, 20));

        System.out.println("=== LOOKUP ===");
        System.out.println("SKU-003: " + catalog.findBySku("SKU-003"));
        System.out.println("SKU-099: " + catalog.findBySku("SKU-099"));

        System.out.println("\n=== STOCK BY CATEGORY ===");
        Map<String, Integer> stockByCat = catalog.stockByCategory();
        // Sort keys for deterministic output
        List<String> cats = new ArrayList<>(stockByCat.keySet());
        Collections.sort(cats);
        for (String cat : cats) {
            System.out.println(cat + ": " + stockByCat.get(cat) + " units");
        }

        System.out.println("\n=== BY CATEGORY ===");
        Map<String, List<Product>> groups = catalog.groupByCategory();
        for (String cat : cats) {
            System.out.println(cat + ": " + groups.get(cat).size() + " products");
        }
    }
}
